sql:
SELECT COUNT(DISTINCT user_id) AS total_active_users
FROM users
WHERE active_status = 'active';

external_knowledge:
- 'A' and 'B' energy efficiency ratings indicate highly energy-efficient buildings;
- 'Average humidity soaring above 80%' refers to buildings with an average humidity greater than 80%;
- 'Exceeding the general warmth of the land' means the average temperature of the building is higher than the overall average temperature from all environmental reports.

sql:
SELECT AVG(active_power) AS average_active_power
FROM sensor_data
WHERE month = 6 AND time BETWEEN 1 AND 24;

external_knowledge:
